// Busca en la libreta 'hojas_clientes' la planilla del cliente por su email
const trigger = $('Nuevo seguimiento en Sheet').first().json;
const email = String(trigger.Email || '').trim().toLowerCase();
const libreta = $input.all().map(function (i) { return i.json; });
const matches = libreta.filter(function (r) { return String(r.Email || '').trim().toLowerCase() === email; });
if (matches.length === 0) {
  throw new Error('No se encontró una planilla para ' + email + '. ¿El cliente generó primero su rutina inicial?');
}
const last = matches[matches.length - 1]; // la más reciente
return { json: {
  ID_Hoja: last.ID_Hoja,
  email: trigger.Email,
  nombre: trigger.Nombre || last.Nombre || 'crack',
  Como_Fue: trigger.Como_Fue || '',
  Peso: trigger.Peso || '',
  Sensaciones: trigger.Sensaciones || '',
  Nueva_Lesion: trigger.Nueva_Lesion || '',
  Cambio_Meta: trigger.Cambio_Meta || ''
} };

// Arma un resumen de texto con lo que el cliente registró en su hoja
const info = $('Buscar planilla del cliente').first().json;
const registros = $input.all().map(function (i) { return i.json; });
let tabla = '';
registros.forEach(function (r) {
  const dia = r['Día'] || '';
  const ej = r['Ejercicio'] || '';
  if (!ej) return;
  tabla += '- [' + dia + '] ' + ej + ': objetivo ' + (r['Series'] || '') + ' x ' + (r['Reps objetivo'] || '') +
    '. Usó ' + (r['Peso usado (kg)'] || '(sin dato)') + ' kg, hizo ' + (r['Reps hechas'] || '(sin dato)') +
    ' reps, dificultad: ' + (r['Dificultad'] || '(sin dato)') + '.\n';
});
if (!tabla) { tabla = '(El cliente aún no registró pesos en su hoja; ajusta según su feedback general.)\n'; }
return { json: {
  email: info.email, nombre: info.nombre, contexto: tabla,
  Como_Fue: info.Como_Fue, Peso: info.Peso, Sensaciones: info.Sensaciones,
  Nueva_Lesion: info.Nueva_Lesion, Cambio_Meta: info.Cambio_Meta
} };

